mapper.insert:
INSERT INTO sys_ai_knowledge_bases( name,
description, created_at, updated_at, created_by, is_active,
) VALUES ( #{name},
#{description}, #{created_at}, #{updated_at}, #{created_by}, #{is_active},
)

mapper.select:
SELECT sys_ai_knowledge_bases.id, name, description, created_at, updated_at, created_by, sys_user.real_name as creatorName, file_count FROM sys_ai_knowledge_bases JOIN ( SELECT id FROM sys_ai_knowledge_bases kmb WHERE 1 = 1
and name like concat('%',#{name},'%')
and created_by = #{owner}
ORDER BY ${orderBy}
ORDER BY id
LIMIT #{page},#{pageSize} ) As tmp on sys_ai_knowledge_bases.id = tmp.id JOIN sys_user on sys_user.ryid = sys_ai_knowledge_bases.created_by WHERE 1 = 1
and name like concat('%',#{name},'%')
and created_by = #{owner}
ORDER BY ${orderBy}

SELECT count(*) FROM sys_ai_knowledge_bases JOIN sys_user ON sys_user.ryid = sys_ai_knowledge_bases.created_by WHERE 1 = 1
AND name LIKE CONCAT('%', #{name}, '%')
AND created_by = #{owner}

SELECT f.id, f.name, f.original_name, f.file_type, f.mime_type, f.size, f.storage_path, f.status, f.uploaded_at, f.uploaded_by, u.real_name AS uploader_name FROM sys_ai_files f LEFT JOIN sys_user u ON u.ryid = f.uploaded_by WHERE f.knowledge_base_id = #{knowledge_base_id} AND f.status != 'deleted'
AND f.original_name LIKE CONCAT('%', #{original_name}, '%')
ORDER BY f.uploaded_at DESC LIMIT #{offset}, #{pageSize}

mapper.update:
UPDATE sys_ai_files SET status = 'deleted'
WHERE id = #{id}
  AND uploaded_by = #{uploaded_by}
